INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-02731', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '司徒達賢撰寫《非營利組織的經營管理》，對於非營利組織的走向與發展提出概念性架構，稱之為 「CORPS」，提供了一套簡易的管理邏輯思考。其中，社會工作管理者是組織決策的核心，其位置在CORPS 中扮演那一項元素的角色？', '["組合人力資源（Participants）", "找尋物力資源（Resources）", "執行有組織的活動（Operations）", "服務社會中的某些人（Clients）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02732', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在所有需求評量方法當中，社會或社區調查可說是最強而有力的需求評量方法，能直接對社區蒐集資 料，也能取得消費者或潛在消費者心態方面的資訊。請問：這種社會調查是屬於下列那一種需求類型 的評量？', '["規範性需求", "感受性需求", "表達性需求", "相對性需求"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02733', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '「人群服務的專家們發現自己身處的時代，可以明顯辨別某一個案派給社會工作者的預期結果，可以追 蹤每一個案投入資源與努力的軌跡，並可以判斷是否達到預期的目標。又可以藉由許多個案所蒐集的資 料，發展出一套如何實際並有效率的幫助那些需要協助的人。」這說明了下列那一方面管理的重要性？', '["總務管理", "資訊管理", "資源管理", "服務管理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02734', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '根據Martin（1993）相關著作，全面品質管理（total quality management, TQM）的哲學原理係有別於傳統 美國式管理之哲學原理。下列那一項敘述屬於全面品質管理之哲學原理？', '["組織有多重的競爭目標", "組織的財務主導組織", "消費者決定何謂品質", "鼓勵承約者以價格相互競爭"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02735', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '所謂的PDCA循環（計畫→行動→查核→處置，plan→do→check→action）的管理模式，其中「計畫」的 重點是策略的陳述、「行動」是策略的執行、「查核」代表評估與管制、「處置」是整體策略的完成。 此循環說明了下列那一項管理的重要性？', '["績效管理", "事務管理", "供應鍊管理", "品質管理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02736', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會服務方案的「運作過程」（throughputs），指的是執行方案所需的各樣程序，包括了處遇、復健、支 持性的活動方法等，如諮商輔導、就業訓練、提供日托、收容安置照顧、食物分送等，為了達成某種程 度的一致性，我們必須確認並界定「運作過程」的構成要素。所謂的「運作過程」要素不包括下列那一 項敘述？', '["服務之定義（service definition）", "服務的工作項目（service tasks）", "處置方法（method of intervention）", "處置效果（intervention effect）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02737', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在臺灣，社會工作者實施社會工作服務時，面臨各種不同的評估，下列有關評估的敘述何者正確？', '["主觀的自我評估並不是社會工作執行各種服務方案後的必要工作", "量化的績效評估通常可以完整地評量社會工作者的服務績效", "行政評估對社會工作者而言，是一種非專業性的評估", "社會工作者的反省力高，主觀的自我評估就能完全改善現有困境，並不需要督導的評論與指正"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02738', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '激勵是一個複雜的心理過程，也是行動的誘因，可導致行為的激發、方向和持續。在當代的激勵理論中， Clayton Alderfer根據實證研究結果，提出人類有三種核心的需求，稱為ERG理論，此三種核心的需求不 包括下列那一項？', '["生存需求", "公平需求", "成長需求", "關係需求"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02739', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '為有效管理勸募行為，妥善運用社會資源，以促進社會公益，保障捐款人權益，政府制定「公益勸募條 例」，該法第5條規定，勸募團體不包括：', '["公立學校", "行政法人", "電視台", "公益性社團法人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02740', 'social-worker', 'social-worker-moex-103-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '隨著臺灣社會環境愈趨複雜，社會工作者所服務的個案、家庭或社區所面臨的問題或需求，會受到所處 環境的影響而有所改變，因此社會工作組織的經營必須隨著服務對象的問題或需求進行變革，下列有關 組織變革（organizational change）的敘述，那一項是社會工作者反對組織變革的理由？', '["組織變革通常從現在的狀態朝向社會工作者所期望的未來而轉變", "組織變革是一個過程，變革的速度通常太慢以致成功機會太低", "社會工作者抗拒組織變革的主要原因是「擔心變革會違反專業倫理」", "在組織變革的過程中，支持與抗拒是難免的，抗拒力量通常會贏過驅動力量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "0cd65457bcf0", "answer_pdf_sha1": "68755a0548ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作管理", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
